import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';

export default function Register() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    locality: 'Kochi, Kerala'
  });

  const handleRegister = (e) => {
    e.preventDefault();
    // In a real app, you'd send data to a server here.
    // For your prototype, we immediately navigate to the dashboard.
    console.log("User Registered:", formData);
    navigate('/dashboard'); 
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <motion.div 
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="bg-white p-10 rounded-[40px] shadow-xl max-w-md w-full border border-slate-100"
      >
        <h2 className="text-3xl font-black text-slate-900 mb-2">Join Wertech</h2>
        <p className="text-slate-500 mb-8 font-medium">Create your hyper-local exchange profile.</p>

        <form onSubmit={handleRegister} className="space-y-4">
          <input 
            type="text" 
            placeholder="Full Name" 
            className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 ring-teal-500 transition-all"
            required
          />
          <input 
            type="email" 
            placeholder="Email Address" 
            className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 ring-teal-500 transition-all"
            required
          />
          <input 
            type="password" 
            placeholder="Password" 
            className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 ring-teal-500 transition-all"
            required
          />
          
          <div className="pt-2">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Initial Locality</p>
            <input 
              type="text" 
              value={formData.locality}
              readOnly
              className="w-full p-4 bg-slate-50 rounded-2xl text-slate-700 font-bold"
            />
          </div>

          <button 
            type="submit"
            className="w-full bg-teal-600 hover:bg-teal-700 text-white font-bold py-4 rounded-2xl mt-6 transition-all shadow-lg shadow-teal-600/20 active:scale-95"
          >
            Create Account
          </button>
        </form>
      </motion.div>
    </div>
  );
}
